#include <iostream>
#include <algorithm>

using namespace std;
using ll = long long;

ll gcd(ll a, ll b) {
    while (b) {
        a %= b;
        swap(a, b);
    }
    return a;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    ll a, b;
    cin >> a >> b;
    ll g = gcd(a, b);
    // a / g * b computed carefully to avoid overflow beyond 64-bit
    // a,b <= 1e9, product up to 1e18 fits in 64-bit signed
    ll lcm = a / g * b;
    cout << lcm << "\n";
    return 0;
}
